// Define the expected output schema for structured JSON
const rcmSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      component: { 
        type: Type.STRING, 
        description: "Standard component name at Level 3/4." 
      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING },
          location: { type: Type.STRING },
          visualCues: { type: Type.STRING }
        },
        required: ["description", "location", "visualCues"]
      },
      function: { type: Type.STRING },
      functionalFailure: { type: Type.STRING },
      failureMode: { type: Type.STRING },
      failureEffect: { type: Type.STRING },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ]
      },
      iso14224Code: { type: Type.STRING },
      criticality: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
      severity: { type: Type.INTEGER },
      occurrence: { type: Type.INTEGER },
      detection: { type: Type.INTEGER },
      maintenanceTask: { type: Type.STRING },
      interval: { type: Type.STRING },
      taskType: {
        type: Type.STRING,
        enum: [
          'Condition Monitoring', 
          'Time-Based', 
          'Run-to-Failure', 
          'Redesign',
          'Failure Finding',
          'Lubrication',
          'Servicing',
          'Restoration',
          'Replacement'
        ]
      }
    },
    required: ["component", "componentIntel", "function", "functionalFailure", "failureMode", "failureEffect", "consequenceCategory", "iso14224Code", "criticality", "severity", "occurrence", "detection", "maintenanceTask", "interval", "taskType"]
  }
};

const inspectionSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    responsibility: { type: Type.STRING },
    estimatedTime: { type: Type.STRING },
    safetyPrecautions: { type: Type.STRING },
    toolsRequired: { type: Type.STRING },
    steps: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          step: { type: Type.INTEGER },
          description: { type: Type.STRING },
          criteria: { type: Type.STRING },
          technique: { type: Type.STRING }
        },
        required: ["step", "description", "criteria", "technique"]
      }
    }
  },
  required: ["responsibility", "estimatedTime", "safetyPrecautions", "toolsRequired", "steps"]
};

export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  language: Language = 'English'
): Promise<RCMItem[]> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API_KEY not set");

    const ai = new GoogleGenAI({ apiKey });
    const parts: any[] = [];

    if (fileData) {
      parts.push({
        inlineData: { mimeType: fileData.mimeType, data: fileData.data }
      });
      parts.push({ text: `Perform a level-4 component decomposition and RCM study based on this document. ALL OUTPUT MUST BE IN ${language.toUpperCase()}.` });
    }

    if (contextText) {
      parts.push({ text: `Operational Context:\n${contextText}\n\nALL OUTPUT MUST BE IN ${language.toUpperCase()}.` });
    }

    parts.push({
      text: `Perform a COMPREHENSIVE and RIGOROUS RCM/FMECA study. 

      MANDATORY: ALL TEXT FIELDS MUST BE IN ${language.toUpperCase()}.

      ANALYSIS SCOPE:
      - Target Volume: Generate approximately 30-35 distinct failure mode items.
      - Component Level: Level 3 or 4.

      Compliance: SAE JA1011 and ISO 14224.`
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: rcmSchema,
        seed: 42, 
        thinkingConfig: { thinkingBudget: 24000 },
        systemInstruction: `You are a Senior Maintenance Engineer. You provide professional RCM reports in ${language}. Your risk assessments are realistic.`
      }
    });

    const rawData = JSON.parse(response.text || "[]") as Omit<RCMItem, 'id' | 'rpn'>[];

    return rawData.map((item, index) => {
      const s = item.severity || 8;
      const o = item.occurrence || 5;
      const d = item.detection || 6;
      return { 
        ...item, 
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        id: `rcm-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 9)}` 
      };
    });

  } catch (error) {
    console.error("RCM Generation Error:", error);
    throw error;
  }
};

export const generateInspectionSheet = async (item: RCMItem, language: Language = 'English'): Promise<InspectionSheet> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API_KEY not set");
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `Create a technical inspection procedure in ${language} for: ${item.maintenanceTask} on ${item.component}.
    Ensure 5 clear technical steps with pass/fail criteria. ALL FIELDS MUST BE IN ${language}.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: inspectionSchema,
        seed: 42,
        thinkingConfig: { thinkingBudget: 4000 },
        systemInstruction: `Technical Procedure Author. Professional and actionable in ${language}.`
      }
    });

    return JSON.parse(response.text || "{}") as InspectionSheet;
  } catch (error) {
    console.error("Inspection Sheet Error", error);
    throw error;
  }
};

