import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { translations } from './services/i18n';
import { RCMItem, FileData, SavedStudy, Language } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2
} from 'lucide-react';

const App: React.FC = () => {
  const [language, setLanguage] = useState<Language>('English');
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  const t = translations[language];

  // Auto-save refs
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
  }, [results, contextText, fileData, studyName, currentStudyId]);

  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      const savedLang = localStorage.getItem('rcm_language') as Language;
      if (savedLang) setLanguage(savedLang);

      try {
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        setError("Could not load saved studies.");
      }
    };
    initData();
  }, []);

  const handleLanguageChange = (lang: Language) => {
    setLanguage(lang);
    localStorage.setItem('rcm_language', lang);
  };

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({ name: file.name, mimeType: file.type, data: base64String });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) { setError("Failed to read file."); }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Provide context.");
      return;
    }
    setIsLoading(true);
    setError(null);
    setResults(null);
    setHistory([]);
    try {
      const data = await generateRCMAnalysis(contextText, fileData, language);
      setResults(data);
    } catch (err: any) {
      setError(err.message || "Error occurred.");
    } finally { setIsLoading(false); }
  };

  const handleSaveStudy = async () => {
    if (!resultsRef.current && !contextTextRef.current && !fileDataRef.current) return;
    const nameToSave = studyNameRef.current.trim() || "Untitled Analysis";
    const idToSave = currentStudyIdRef.current || `study-${Date.now()}`;
    const newStudy: SavedStudy = {
      id: idToSave, name: nameToSave, timestamp: Date.now(),
      items: resultsRef.current || [], contextText: contextTextRef.current,
      fileName: fileDataRef.current?.name
    };
    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentStudyIdRef.current) setCurrentStudyId(idToSave);
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) { setError("Failed to save."); }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items);
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    setIsSidebarOpen(false);
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setIsSidebarOpen(false);
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) setHistory(prev => [...prev.slice(-29), results]);
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal
        isOpen={showWelcome}
        onClose={handleCloseWelcome}
        language={language}
        onLanguageChange={handleLanguageChange}
      />
      <SODReference 
        isOpen={showSODReference} 
        onClose={() => setShowSODReference(false)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
        language={language}
      />
      <OperationalContextBuilder 
        isOpen={showContextBuilder} 
        onClose={() => setShowContextBuilder(false)} 
        onComplete={(builtContext) => setContextText(builtContext)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
        language={language}
      />
      <DecisionLogicModal 
        isOpen={showDecisionLogic} 
        onClose={() => setShowDecisionLogic(false)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
        language={language}
      />
      <AICopilot data={results} onUpdate={handleResultsUpdate} language={language} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies}
          currentStudyId={currentStudyId}
          onSelect={handleLoadStudy}
          onDelete={id => deleteStudyFromDB(id).then(() => getAllStudies().then(setSavedStudies))}
          onNew={handleNewStudy}
          language={language}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6">
                  <Cpu size={22} className="text-indigo-400 group-hover:text-white" />
                </div>
                <div className="flex flex-col">
                  <span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span>
                  <div className="flex items-center gap-1 mt-1">
                    <span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none uppercase">GENERATOR</span>
                  </div>
                </div>
              </div>
              <div className="flex flex-col min-w-0">
                 <input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent focus:outline-none w-full sm:w-80 truncate" />
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />{t.ui.sodGuide}</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />{t.ui.logicTree}</button>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200' : 'text-slate-200'}`}><Undo2 size={20} /></button>
                <button onClick={handleSaveStudy} disabled={!results && !contextText} className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-50 text-emerald-600' : 'bg-indigo-600 text-white'}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? t.ui.analysisSaved : t.ui.saveStudy}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
