                    {isLoading ? t.ui.runningEngine : t.ui.initiateFmea}
                  </button>
                </div>
              </div>
            </div>

            {results && <AnalysisResult data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} language={language} />}
          </div>
        </main>
      </div>
    </div>
  );
};

