            </thead>
            <tbody className="divide-y divide-slate-100 text-sm bg-white">
              {processedData.map((item) => (
                <tr key={item.id} className="hover:bg-slate-50">
                  <td className="px-6 py-4 font-medium text-xs">{item.component}</td>
                  <td className="px-6 py-4 text-[10px]">{item.consequenceCategory}</td>
                  <td className="px-6 py-4 text-[11px] font-semibold">{item.failureMode}</td>
                  <td className="px-4 py-4 font-bold">{item.rpn}</td>
