                  <td className="px-6 py-4 text-center">
                    <button onClick={() => setViewSheet({ item })} className="text-emerald-500"><FileCheck size={20} /></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
