        <button
          onClick={onNew}
          className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-3 px-4 rounded-lg text-sm font-medium transition-all shadow-md shadow-indigo-200 active:scale-95"
        >
          <Plus size={18} />
